// Enhanced NIFTY Option Chain Builder using Dhan Instrument Master
const csvData = $node['Get Dhan Instrument Master'].json;
const spotPrice = parseFloat($node['Get NIFTY LTP'].json.data.LTP);
const accessToken = $node['Dhan Authentication'].json.data.access_token;

// Parse CSV data to extract NIFTY options
const lines = csvData.split('\n');
const headers = lines[0].split(',');

// Find relevant column indices
const securityIdIndex = headers.indexOf('SEM_SECURITY_ID');
const tradingSymbolIndex = headers.indexOf('SEM_TRADING_SYMBOL');
const instrumentIndex = headers.indexOf('SEM_INSTRUMENT_NAME');
const strikeIndex = headers.indexOf('SEM_STRIKE_PRICE');
const expiryIndex = headers.indexOf('SEM_EXPIRY_DATE');
const lotSizeIndex = headers.indexOf('SEM_LOT_SIZE');

// Get current Thursday expiry for NIFTY (weekly expiry)
const today = new Date();
const nextThursday = new Date(today);
const daysUntilThursday = (4 - today.getDay() + 7) % 7;

if (daysUntilThursday === 0 && today.getHours() >= 15) {
  nextThursday.setDate(today.getDate() + 7);
} else {
  nextThursday.setDate(today.getDate() + daysUntilThursday);
}

const expiryDateStr = nextThursday.toISOString().split('T')[0];

// Filter NIFTY options for current expiry
const niftyOptions = [];
const atmStrike = Math.round(spotPrice / 50) * 50; // NIFTY strikes are in multiples of 50

for (let i = 1; i < lines.length; i++) {
  const row = lines[i].split(',');

  if (row.length < headers.length) continue;

  const instrument = row[instrumentIndex];
  const tradingSymbol = row[tradingSymbolIndex];
  const strike = parseFloat(row[strikeIndex]);
  const expiry = row[expiryIndex];
  const securityId = row[securityIdIndex];
  const lotSize = parseInt(row[lotSizeIndex]);

  // Filter for NIFTY options with current expiry
  if (instrument === 'OPTIDX' && 
      tradingSymbol.startsWith('NIFTY') && 
      !tradingSymbol.startsWith('NIFTYBANK') && // Exclude Bank Nifty
      expiry === expiryDateStr &&
      strike >= atmStrike - 300 && 
      strike <= atmStrike + 300) {

    const optionType = tradingSymbol.includes('CE') ? 'CE' : 'PE';

    niftyOptions.push({
      securityId: securityId,
      tradingSymbol: tradingSymbol,
      strike: strike,
      optionType: optionType,
      expiry: expiry,
      lotSize: lotSize,
      distanceFromATM: Math.abs(strike - atmStrike)
    });
  }
}

// Sort by distance from ATM
niftyOptions.sort((a, b) => a.distanceFromATM - b.distanceFromATM);

// Separate CE and PE options
const ceOptions = niftyOptions.filter(opt => opt.optionType === 'CE').slice(0, 10);
const peOptions = niftyOptions.filter(opt => opt.optionType === 'PE').slice(0, 10);

// Get LTP for top options
async function getOptionLTP(securityId) {
  try {
    const response = await fetch(`https://api.dhan.co/v2/marketfeed/ltp?securityId=${securityId}&exchangeSegment=NSE_FNO&instrument=OPTIDX`, {
      headers: {
        'access-token': accessToken,
        'Content-Type': 'application/json'
      }
    });

    if (response.ok) {
      const data = await response.json();
      return data.data.LTP || 0;
    }
  } catch (error) {
    console.error(`Error fetching LTP for ${securityId}:`, error);
  }
  return 0;
}

// Fetch LTP for CE options
const ceOptionsWithLTP = [];
for (const option of ceOptions) {
  const ltp = await getOptionLTP(option.securityId);
  ceOptionsWithLTP.push({
    ...option,
    ltp: ltp,
    volume: 0,
    openInterest: 0
  });
}

// Fetch LTP for PE options
const peOptionsWithLTP = [];
for (const option of peOptions) {
  const ltp = await getOptionLTP(option.securityId);
  peOptionsWithLTP.push({
    ...option,
    ltp: ltp,
    volume: 0,
    openInterest: 0
  });
}

return {
  spotPrice: spotPrice,
  atmStrike: atmStrike,
  expiry: expiryDateStr,
  ceOptions: ceOptionsWithLTP,
  peOptions: peOptionsWithLTP,
  totalOptionsFound: niftyOptions.length,
  underlying: 'NIFTY',
  lotSize: 50, // NIFTY lot size
  timestamp: new Date().toISOString()
};

// Enhanced Technical Indicators for NIFTY Trading
const ohlcData = $node['Get NIFTY OHLC Data'].json.data || [];
const currentPrice = parseFloat($node['Get NIFTY LTP'].json.data.LTP);
const vix = parseFloat($node['Get India VIX Data'].json.data.LTP);

// RSI Calculation (14 period)
function calculateRSI(prices, period = 14) {
  if (prices.length < period + 1) return 50;

  const gains = [];
  const losses = [];

  for (let i = 1; i < prices.length; i++) {
    const change = prices[i] - prices[i-1];
    gains.push(change > 0 ? change : 0);
    losses.push(change < 0 ? Math.abs(change) : 0);
  }

  const avgGain = gains.slice(-period).reduce((a, b) => a + b, 0) / period;
  const avgLoss = losses.slice(-period).reduce((a, b) => a + b, 0) / period;

  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

// MACD Calculation
function calculateEMA(prices, period) {
  if (prices.length === 0) return 0;
  const k = 2 / (period + 1);
  let ema = prices[0];
  for (let i = 1; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return ema;
}

function calculateMACD(prices) {
  if (prices.length < 26) return { macd: 0, signal: 0, histogram: 0 };

  const ema12 = calculateEMA(prices, 12);
  const ema26 = calculateEMA(prices, 26);
  const macd = ema12 - ema26;

  const macdLine = [macd];
  const signal = calculateEMA(macdLine, 9);

  return {
    macd: macd,
    signal: signal,
    histogram: macd - signal
  };
}

// Volume Analysis for NIFTY
function calculateVolumeRatio(ohlcData) {
  if (ohlcData.length < 20) return 1.0;

  const currentVolume = parseFloat(ohlcData[ohlcData.length - 1].volume || 0);
  const avgVolume = ohlcData.slice(-20).reduce((sum, candle) => 
    sum + parseFloat(candle.volume || 0), 0) / 20;

  return avgVolume > 0 ? currentVolume / avgVolume : 1.0;
}

// Momentum Calculation
function calculateMomentum(prices, period = 10) {
  if (prices.length < period) return 0;
  const current = prices[prices.length - 1];
  const previous = prices[prices.length - period];
  return previous > 0 ? ((current - previous) / previous) * 100 : 0;
}

// NIFTY-specific Candle Pattern Detection
function detectCandlePattern(candle) {
  if (!candle) return "NORMAL";

  const open = parseFloat(candle.open || 0);
  const high = parseFloat(candle.high || 0);
  const low = parseFloat(candle.low || 0);
  const close = parseFloat(candle.close || 0);

  const body = Math.abs(close - open);
  const upperShadow = high - Math.max(open, close);
  const lowerShadow = Math.min(open, close) - low;
  const totalRange = high - low;

  if (totalRange === 0) return "NORMAL";

  // NIFTY-specific pattern thresholds
  const bodyRatio = body / totalRange;
  const upperShadowRatio = upperShadow / body;
  const lowerShadowRatio = lowerShadow / body;

  if (bodyRatio < 0.1) return "DOJI";
  if (lowerShadowRatio > 2 && upperShadowRatio < 0.5) return "HAMMER";
  if (upperShadowRatio > 2 && lowerShadowRatio < 0.5) return "SHOOTING_STAR";
  if (upperShadow < totalRange * 0.05 && lowerShadow < totalRange * 0.05) return "MARUBOZU";

  return "NORMAL";
}

// NIFTY Market Strength Analysis
function analyzeNiftyMarketStrength(rsi, macd, momentum, volumeRatio, vix) {
  let strength = 0;
  let signals = [];

  // RSI Analysis for NIFTY
  if (rsi < 35) {
    strength += 2;
    signals.push("NIFTY_RSI_OVERSOLD");
  } else if (rsi > 65) {
    strength -= 2;
    signals.push("NIFTY_RSI_OVERBOUGHT");
  }

  // MACD Analysis
  if (macd.macd > 0 && macd.histogram > 0) {
    strength += 1.5;
    signals.push("NIFTY_MACD_BULLISH");
  } else if (macd.macd < 0 && macd.histogram < 0) {
    strength -= 1.5;
    signals.push("NIFTY_MACD_BEARISH");
  }

  // NIFTY Momentum Analysis
  if (momentum > 1.5) {
    strength += 1;
    signals.push("NIFTY_MOMENTUM_BULLISH");
  } else if (momentum < -1.5) {
    strength -= 1;
    signals.push("NIFTY_MOMENTUM_BEARISH");
  }

  // Volume Analysis
  if (volumeRatio > 1.3) {
    strength += 0.5;
    signals.push("NIFTY_VOLUME_SURGE");
  }

  // VIX Impact on NIFTY
  if (vix > 20) {
    strength *= 0.8; // Reduce strength in high volatility
    signals.push("HIGH_VIX_CAUTION");
  }

  return { strength, signals };
}

// Extract and calculate indicators
const closePrices = ohlcData.map(d => parseFloat(d.close || 0)).filter(p => p > 0);
const lastCandle = ohlcData[ohlcData.length - 1];

const rsi = calculateRSI(closePrices);
const macd = calculateMACD(closePrices);
const momentum = calculateMomentum(closePrices);
const volumeRatio = calculateVolumeRatio(ohlcData);
const candlePattern = detectCandlePattern(lastCandle);
const marketAnalysis = analyzeNiftyMarketStrength(rsi, macd, momentum, volumeRatio, vix);

// Get sentiment from previous node
const sentiment = $node['Market Sentiment API'].json.sentiment || 'NEUTRAL';

// Compile NIFTY-specific indicators
const indicators = {
  // Basic Indicators
  rsi: Math.round(rsi * 100) / 100,
  macd: {
    macd: Math.round(macd.macd * 100) / 100,
    signal: Math.round(macd.signal * 100) / 100,
    histogram: Math.round(macd.histogram * 100) / 100
  },
  momentum: Math.round(momentum * 100) / 100,
  volumeRatio: Math.round(volumeRatio * 100) / 100,

  // Market Data
  spotPrice: currentPrice,
  vix: vix,
  sentiment: sentiment,
  candlePattern: candlePattern,
  underlying: 'NIFTY',

  // Analysis Results
  marketStrength: Math.round(marketAnalysis.strength * 100) / 100,
  detectedSignals: marketAnalysis.signals,
  signalCount: marketAnalysis.signals.length,

  // NIFTY Market Conditions
  volatilityRegime: vix > 20 ? "HIGH" : vix > 15 ? "MEDIUM" : "LOW",
  trendDirection: marketAnalysis.strength > 1 ? "BULLISH" : 
                  marketAnalysis.strength < -1 ? "BEARISH" : "SIDEWAYS",

  // Additional Context
  timestamp: new Date().toISOString(),
  dataPoints: closePrices.length,
  priceChange: closePrices.length > 1 ? 
    Math.round(((closePrices[closePrices.length - 1] - closePrices[closePrices.length - 2]) / 
    closePrices[closePrices.length - 2]) * 10000) / 100 : 0
};

return { indicators };

// Enhanced NIFTY Writers Zone Detection with Premium Analysis
const optionChainData = $node['Build NIFTY Option Chain'].json;
const ceOptions = optionChainData.ceOptions || [];
const peOptions = optionChainData.peOptions || [];
const spotPrice = optionChainData.spotPrice;
const atmStrike = optionChainData.atmStrike;

// Initialize analysis variables
let maxCELTP = 0;
let maxPELTP = 0;
let maxCEStrike = 0;
let maxPEStrike = 0;
let totalCEValue = 0;
let totalPEValue = 0;

// Arrays to store option data for analysis
const ceAnalysis = [];
const peAnalysis = [];

// Process CE Options
ceOptions.forEach(option => {
  const strike = option.strike;
  const ltp = option.ltp;

  if (strike > 0 && ltp > 0) {
    ceAnalysis.push({ strike, ltp, type: 'CE', distanceFromATM: option.distanceFromATM });
    totalCEValue += ltp;

    if (ltp > maxCELTP) {
      maxCELTP = ltp;
      maxCEStrike = strike;
    }
  }
});

// Process PE Options
peOptions.forEach(option => {
  const strike = option.strike;
  const ltp = option.ltp;

  if (strike > 0 && ltp > 0) {
    peAnalysis.push({ strike, ltp, type: 'PE', distanceFromATM: option.distanceFromATM });
    totalPEValue += ltp;

    if (ltp > maxPELTP) {
      maxPELTP = ltp;
      maxPEStrike = strike;
    }
  }
});

// Calculate Put-Call Premium Ratio for NIFTY
const putCallPremiumRatio = totalCEValue > 0 ? totalPEValue / totalCEValue : 1.0;

// NIFTY-specific Writers Zone Analysis
function analyzeNiftyWritersZone() {
  let analysis = {
    zone: 'NEUTRAL',
    confidence: 0,
    reasoning: [],
    supportLevels: [],
    resistanceLevels: [],
    marketStructure: 'BALANCED'
  };

  // NIFTY-specific analysis thresholds
  const niftyVolatilityFactor = spotPrice > 20000 ? 100 : 50;

  // Price position analysis for NIFTY
  if (spotPrice > atmStrike + niftyVolatilityFactor) {
    analysis.zone = 'BULLISH';
    analysis.confidence += 0.3;
    analysis.reasoning.push('NIFTY trading significantly above ATM');
  } else if (spotPrice < atmStrike - niftyVolatilityFactor) {
    analysis.zone = 'BEARISH';
    analysis.confidence += 0.3;
    analysis.reasoning.push('NIFTY trading significantly below ATM');
  }

  // NIFTY Premium Ratio Analysis
  if (putCallPremiumRatio > 1.15) {
    analysis.marketStructure = 'PUT_PREMIUM_HIGH';
    if (analysis.zone === 'BEARISH') {
      analysis.confidence += 0.3;
      analysis.reasoning.push('High Put premium confirms NIFTY bearish sentiment');
    } else if (analysis.zone === 'NEUTRAL') {
      analysis.zone = 'BEARISH';
      analysis.confidence += 0.2;
      analysis.reasoning.push('High Put premium suggests NIFTY bearish bias');
    }
  } else if (putCallPremiumRatio < 0.85) {
    analysis.marketStructure = 'CALL_PREMIUM_HIGH';
    if (analysis.zone === 'BULLISH') {
      analysis.confidence += 0.3;
      analysis.reasoning.push('High Call premium confirms NIFTY bullish sentiment');
    } else if (analysis.zone === 'NEUTRAL') {
      analysis.zone = 'BULLISH';
      analysis.confidence += 0.2;
      analysis.reasoning.push('High Call premium suggests NIFTY bullish bias');
    }
  } else {
    analysis.marketStructure = 'BALANCED';
    analysis.reasoning.push('Balanced NIFTY premium distribution');
  }

  // ATM Analysis for NIFTY
  const atmCE = ceOptions.find(opt => opt.strike === atmStrike);
  const atmPE = peOptions.find(opt => opt.strike === atmStrike);

  if (atmCE && atmPE) {
    const atmSkew = atmCE.ltp / atmPE.ltp;
    if (atmSkew > 1.15) {
      analysis.confidence += 0.1;
      analysis.reasoning.push('NIFTY ATM Call premium higher (bullish skew)');
    } else if (atmSkew < 0.85) {
      analysis.confidence += 0.1;
      analysis.reasoning.push('NIFTY ATM Put premium higher (bearish skew)');
    }
  }

  // NIFTY Support and Resistance Levels
  const sortedPEStrikes = peOptions
    .filter(opt => opt.strike <= spotPrice && opt.ltp > 3)
    .sort((a, b) => b.ltp - a.ltp)
    .slice(0, 3)
    .map(opt => opt.strike);

  const sortedCEStrikes = ceOptions
    .filter(opt => opt.strike >= spotPrice && opt.ltp > 3)
    .sort((a, b) => b.ltp - a.ltp)
    .slice(0, 3)
    .map(opt => opt.strike);

  analysis.supportLevels = sortedPEStrikes;
  analysis.resistanceLevels = sortedCEStrikes;

  // Final confidence adjustment
  analysis.confidence = Math.min(analysis.confidence, 1.0);

  if (analysis.confidence < 0.3) {
    analysis.zone = 'NEUTRAL';
    analysis.reasoning.push('Insufficient conviction for NIFTY directional bias');
  }

  return analysis;
}

// Perform the analysis
const writersAnalysis = analyzeNiftyWritersZone();

// Compile comprehensive results
const result = {
  // Primary Results
  writersZone: writersAnalysis.zone,
  confidence: Math.round(writersAnalysis.confidence * 100) / 100,

  // Premium Data
  maxCELTP: maxCELTP,
  maxPELTP: maxPELTP,
  maxCEStrike: maxCEStrike,
  maxPEStrike: maxPEStrike,
  totalCEValue: Math.round(totalCEValue * 100) / 100,
  totalPEValue: Math.round(totalPEValue * 100) / 100,
  putCallPremiumRatio: Math.round(putCallPremiumRatio * 100) / 100,

  // Significant Levels
  supportLevels: writersAnalysis.supportLevels,
  resistanceLevels: writersAnalysis.resistanceLevels,

  // Analysis Details
  reasoning: writersAnalysis.reasoning,
  marketStructure: writersAnalysis.marketStructure,

  // Market Context
  currentPrice: spotPrice,
  atmStrike: atmStrike,
  distanceFromATM: Math.abs(spotPrice - atmStrike),
  underlying: 'NIFTY',

  // Statistics
  ceOptionsAnalyzed: ceAnalysis.length,
  peOptionsAnalyzed: peAnalysis.length,

  // Timestamp
  timestamp: new Date().toISOString()
};

return result;

// Enhanced NIFTY Strike Selection and Order Preparation for Dhan
const signal = $node['AI NIFTY Trade Confirmation'].json.signal;
const optionChainData = $node['Build NIFTY Option Chain'].json;
const spotPrice = optionChainData.spotPrice;
const atmStrike = optionChainData.atmStrike;
const ceOptions = optionChainData.ceOptions;
const peOptions = optionChainData.peOptions;

let selectedOption;
let orderType;
let quantity = 50; // NIFTY lot size

// NIFTY-specific option selection logic
if (signal === 'BUY_CE') {
  // Select ATM or slightly OTM CE for NIFTY
  selectedOption = ceOptions.find(opt => opt.strike === atmStrike) || 
                   ceOptions.find(opt => opt.strike === atmStrike + 50) ||
                   ceOptions[0];
  orderType = 'BUY';
} else if (signal === 'BUY_PE') {
  // Select ATM or slightly OTM PE for NIFTY
  selectedOption = peOptions.find(opt => opt.strike === atmStrike) || 
                   peOptions.find(opt => opt.strike === atmStrike - 50) ||
                   peOptions[0];
  orderType = 'BUY';
} else {
  throw new Error('Invalid signal: ' + signal);
}

if (!selectedOption) {
  throw new Error('No suitable NIFTY option found for signal: ' + signal);
}

// Validate NIFTY option has reasonable premium
if (selectedOption.ltp < 3) {
  throw new Error(`NIFTY option premium too low: ${selectedOption.ltp}`);
}

// Create Dhan order object for NIFTY
const dhanOrder = {
  "securityId": selectedOption.securityId,
  "exchangeSegment": "NSE_FNO",
  "transactionType": orderType,
  "quantity": quantity,
  "orderType": "MARKET",
  "productType": "INTRADAY",
  "price": 0,
  "triggerPrice": 0,
  "disclosedQuantity": 0,
  "validity": "DAY",
  "afterMarketOrder": false,
  "boProfitValue": 0,
  "boStopLossValue": 0
};

// Return comprehensive NIFTY order data
return {
  // Order Details
  dhanOrder: dhanOrder,
  selectedOption: selectedOption,
  signal: signal,
  orderType: orderType,
  quantity: quantity,
  underlying: 'NIFTY',

  // Market Context
  spotPrice: spotPrice,
  atmStrike: atmStrike,
  selectedStrike: selectedOption.strike,
  expectedPremium: selectedOption.ltp,

  // Risk Metrics
  maxLoss: selectedOption.ltp * quantity,
  breakeven: selectedOption.optionType === 'CE' ? 
    selectedOption.strike + selectedOption.ltp :
    selectedOption.strike - selectedOption.ltp,

  // Additional Info
  optionType: selectedOption.optionType,
  expiry: selectedOption.expiry,
  tradingSymbol: selectedOption.tradingSymbol,
  lotSize: quantity,
  timestamp: new Date().toISOString()
};

// Enhanced NIFTY SL & Target Calculation for Dhan
const orderStatus = $node['Get NIFTY Order Status'].json.data;
const orderData = $node['Prepare NIFTY Dhan Order'].json;

// Validate order execution
if (orderStatus.orderStatus !== 'TRADED') {
  throw new Error(`NIFTY order not executed. Status: ${orderStatus.orderStatus}`);
}

// Get execution details
const fillPrice = parseFloat(orderStatus.price);
const quantity = parseInt(orderStatus.quantity);
const securityId = orderStatus.securityId;
const tradingSymbol = orderData.selectedOption.tradingSymbol;

// Validate fill price
if (!fillPrice || fillPrice <= 0) {
  throw new Error(`Invalid NIFTY fill price: ${fillPrice}`);
}

// NIFTY-specific SL and Target calculation
const niftyStopLossPoints = 12;  // 12 points SL for NIFTY
const niftyTargetPoints = 25;    // 25 points target for NIFTY

const stopLossPrice = Math.max(fillPrice - niftyStopLossPoints, 0.5);
const targetPrice = fillPrice + niftyTargetPoints;

// Create Stop Loss Order for NIFTY
const stopLossOrder = {
  "securityId": securityId,
  "exchangeSegment": "NSE_FNO",
  "transactionType": "SELL",
  "quantity": quantity,
  "orderType": "SL-M",
  "productType": "INTRADAY",
  "price": 0,
  "triggerPrice": stopLossPrice,
  "disclosedQuantity": 0,
  "validity": "DAY",
  "afterMarketOrder": false,
  "boProfitValue": 0,
  "boStopLossValue": 0
};

// Create Target Order for NIFTY
const targetOrder = {
  "securityId": securityId,
  "exchangeSegment": "NSE_FNO",
  "transactionType": "SELL",
  "quantity": quantity,
  "orderType": "LIMIT",
  "productType": "INTRADAY",
  "price": targetPrice,
  "triggerPrice": 0,
  "disclosedQuantity": 0,
  "validity": "DAY",
  "afterMarketOrder": false,
  "boProfitValue": 0,
  "boStopLossValue": 0
};

// Calculate NIFTY risk metrics
const riskAmount = fillPrice - stopLossPrice;
const rewardAmount = targetPrice - fillPrice;
const riskRewardRatio = riskAmount > 0 ? rewardAmount / riskAmount : 0;

// Return comprehensive NIFTY exit strategy data
return {
  // Entry Details
  entryOrderId: orderStatus.orderId,
  fillPrice: fillPrice,
  quantity: quantity,
  securityId: securityId,
  tradingSymbol: tradingSymbol,
  underlying: 'NIFTY',

  // Exit Levels
  stopLoss: stopLossPrice,
  target: targetPrice,

  // Order Objects
  stopLossOrder: stopLossOrder,
  targetOrder: targetOrder,

  // Risk Metrics
  riskAmount: Math.round(riskAmount * 100) / 100,
  rewardAmount: Math.round(rewardAmount * 100) / 100,
  riskRewardRatio: Math.round(riskRewardRatio * 100) / 100,
  maxLoss: Math.round(riskAmount * quantity * 100) / 100,
  maxProfit: Math.round(rewardAmount * quantity * 100) / 100,

  // Execution Details
  executionTime: orderStatus.createTime,
  orderStatus: orderStatus.orderStatus,
  exchangeOrderId: orderStatus.exchangeOrderId,

  // Timestamp
  timestamp: new Date().toISOString()
};
